const memBase = "/Users/zchee/src/github.com/zchee/dotfiles/.config/codex/memories";
const results = [];
async function run(name, args) {
  const out = await tools.shell_command({command: args.command, workdir: args.workdir || cwd, timeout_ms: args.timeout_ms || 10000});
  results.push(`## ${name}\n${typeof out === "string" ? out : JSON.stringify(out)}`);
}
