  command: `rg --threads=8 -n "history-compact|CODEX_HOME|history compact" ${memBase}/MEMORY.md || true`,
  workdir: cwd,
});
await run("repo search", {
  command: `rg --threads=8 -n "history-compact|CODEX_HOME" codex/scripts codex/tests .omx || true`,
  workdir: cwd,
});
